import{c as t,Q as r,j as s,m as o}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"How do I churn a customer?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/churn-customer.md","filePath":"guide/recipes/admin/churn-customer.md","lastUpdated":1779094756000}'),a={name:"guide/recipes/admin/churn-customer.md"};function n(i,e,c,l,u,d){return r(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="how-do-i-churn-a-customer" tabindex="-1">How do I churn a customer? <a class="header-anchor" href="#how-do-i-churn-a-customer" aria-label="Permalink to &quot;How do I churn a customer?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Account Manager</strong> (within scope)</p></div><p>Churning ends the customer relationship. It&#39;s the right state for &quot;they cancelled&quot; — distinct from <strong>suspended</strong> which is temporary.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Customers</strong> and click the customer.</li><li>Click <strong>Churn Customer</strong> in the actions menu.</li><li>Enter a <strong>reason</strong> (used in churn reporting).</li><li>Confirm.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><ul><li>The customer record moves to status <strong>Churned</strong>.</li><li>Portal access is blocked for all of the customer&#39;s users.</li><li>The customer is excluded from active-customer dashboards and revenue calculations.</li><li>Tenants and instances are preserved for the agreed data-retention period, then purged.</li></ul><div class="warning custom-block"><p class="custom-block-title">Churn is not the same as delete</p><p>Customer data is retained for compliance. To purge, contact engineering after the retention window passes.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./suspend-customer">How do I suspend a customer?</a></li></ul>',10)])])}const p=t(a,[["render",n]]);export{m as __pageData,p as default};
